B.a11=new A.bm(3,"Conteo de Figuras","\xbfCu\xe1ntos tri\xe1ngulos (de todos los tama\xf1os) puedes contar en la figura?","assets/figuras_psicometrico/conteo/q03_secuencia.svg",B.UX,"B","Hay 5 tri\xe1ngulos en total: 1 grande, 2 medianos (izquierdo y derecho) y 2 peque\xf1os internos formados por las subdivisiones. La respuesta correcta es 5.","conteo")
B.V3=new A.aP(B.U,["assets/figuras_psicometrico/rotacion/q04_opcion_a.svg","assets/figuras_psicometrico/rotacion/q04_opcion_b.svg","assets/figuras_psicometrico/rotacion/q04_opcion_c.svg","assets/figuras_psicometrico/rotacion/q04_opcion_d.svg","assets/figuras_psicometrico/rotacion/q04_opcion_e.svg"],t.l)
B.a0K=new A.bm(4,"Completar Patr\xf3n","La flecha rota 90\xb0 en sentido horario cada paso. \xbfCu\xe1l es la figura que falta?","assets/figuras_psicometrico/rotacion/q04_secuencia.svg",B.V3,"D","La flecha parte apuntando arriba (\u2191), luego gira 90\xb0 horario: -> derecha, -> abajo, y finalmente -> izquierda. La opci\xf3n D muestra la flecha apuntando a la izquierda.","rotacion")
B.Vl=new A.aP(B.U,["assets/figuras_psicometrico/serie/q05_opcion_a.svg","assets/figuras_psicometrico/serie/q05_opcion_b.svg","assets/figuras_psicometrico/serie/q05_opcion_c.svg","assets/figuras_psicometrico/serie/q05_opcion_d.svg","assets/figuras_psicometrico/serie/q05_opcion_e.svg"],t.l)
B.a0l=new A.bm(5,"Series de Domin\xf3","Cada ficha sigue un patr\xf3n incremental en ambas partes (arriba y abajo). \xbfQu\xe9 ficha sigue?","assets/figuras_psicometrico/serie/q05_secuencia.svg",B.Vl,"A","Patr\xf3n Arriba: 1 -> 2 -> 3 -> (4). Patr\xf3n Abajo: 2 -> 3 -> 4 -> (5). La ficha resultante es 4/5, que corresponde a la opci\xf3n A.","serie")
